import { useState, useEffect, useCallback } from 'react';
import { YMaps, Map, Placemark } from '@pbe/react-yandex-maps';

import BaseTamplate from '../consts/BaseTamplate';
import { readRows } from '../consts/crud';


function Home() {
    const [tableData, setTableData] = useState([]);
    const [loading, setLoading] = useState(false);

    const fetchTableData = useCallback(async () => {
        setLoading(true);

        const localities_crossroads = await readRows('/localities/crossroads/roads/sings');
        setTableData(Array.isArray(localities_crossroads) ? localities_crossroads : [localities_crossroads]);

        setLoading(false);
    }, []);

    useEffect(() => {
        fetchTableData();
    }, [fetchTableData]);


    const informationRoadSing = (marker) => {
        return `
            <div>
                <div>
                    <img src='img/${marker.crossroads.roads.sings.image}' />
                </div>
                <div>
                    <h3>
                        ${marker.crossroads.roads.sings.name_sing}
                    </h3>
                    <div>
                        <div>
                            <div>
                                <div style='font-weight: bold;'>
                                    Широта
                                </div>
                                <div>
                                    ${marker.crossroads.roads.sings.latitude.toFixed(6)}
                                </div>
                            </div>
                            <div>
                                <div style='font-weight: bold;'>
                                    Долгота
                                </div>
                                <div>
                                    ${marker.crossroads.roads.sings.longitude.toFixed(6)}
                                </div>
                            </div>
                            <div>
                                <div>
                                    <div style='font-weight: bold;'>
                                        Населенный пункт:
                                    </div>
                                    <div>
                                        ${marker.name_locality}
                                    </div>
                                </div>
                            </div>
                            <div>
                                <div>
                                    <div style='font-weight: bold;'>
                                        Тип перекрестка:
                                    </div>
                                    <div>
                                        ${marker.crossroads.type_crossroad}
                                    </div>
                                </div>
                            </div>
                            <div>
                                <div>
                                    <div style='font-weight: bold;'>
                                        Дорога:
                                    </div>
                                    <div>
                                        ${marker.crossroads.roads.number_road},
                                        ${marker.crossroads.roads.name_road}
                                    </div>
                                </div>
                            </div>
                        </div>
                    </div>
                </div>
            </div>
        `;
    };

    return (
        <div> 
            { loading ? (
                <div>
                    <p>Загрузка данных...</p>
                </div>
            ) : localStorage.getItem('login') != '' ? (
                <div>
                    <BaseTamplate />

                    <div className='container'>
                        <h1>Интерактивная карта.</h1>
                        <div style={{ 
                            width: '100%', 
                            height: '600px',
                        }}>
                            <YMaps>
                                <Map 
                                    state={{center: [55.751574, 37.573856], zoom: 10 }} 
                                    width='100%' 
                                    height='100%'
                                >
                                {tableData[0]?.items.map((marker) => (
                                    <Placemark
                                        key={marker.id}
                                        geometry={[marker.crossroads.roads.sings.latitude, marker.crossroads.roads.sings.longitude]}
                                        options={{
                                            iconLayout: 'default#image',
                                            iconImageSize: [48, 48],
                                            iconImageOffset: [-24, -48],
                                            hideIconOnBalloonOpen: false,
                                            openBalloonOnClick: true,
                                        }}
                                        properties={{
                                            hintContent: `<div>${marker.crossroads.roads.sings.name_sing}</div>`,
                                            balloonContent: informationRoadSing(marker),
                                        }}
                                        modules={['geoObject.addon.balloon']}
                                        onClick={() => {
                                            console.log('Выбран маркер:', marker.name_locality);
                                        }}
                                    />
                                ))}
                                </Map>
                            </YMaps>
                        </div>
                    </div>
                </div>
            ) : (
                <p className='no-data'>Нет данных для отображения</p> 
            )} 
        </div>
    );
}

export default Home;
